// TestUpsertBatch_TypedFailureDoesNotStrandZonesSecondaryDnsGeneric exercises
// the savepoint isolation around the typed-table dispatch. The fixture omits
// the NOT NULL parent FK column so the typed insert fails; the savepoint
// rolls back only the typed projection. The generic resources row inserted
// just before must survive. Regression for issue #1392, where a single
// outer transaction caused typed-table failures to cascade and silently
// discard every successfully fetched API row.
func TestUpsertBatch_TypedFailureDoesNotStrandZonesSecondaryDnsGeneric(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	// Items deliberately omit "zones_id" so the typed NOT NULL
	// constraint fires.
	items := []json.RawMessage{
		json.RawMessage(`{"id": "orphan-001"}`),
		json.RawMessage(`{"id": "orphan-002"}`),
		json.RawMessage(`{"id": "orphan-003"}`),
	}
	stored, extractFailures, err := s.UpsertBatch("zones_secondary_dns", items)
	if err != nil {
		t.Fatalf("UpsertBatch: %v (typed-table failure must not propagate)", err)
	}
	if stored != len(items) {
		t.Fatalf("stored = %d, want %d (generic resources rows must land even when typed table fails)", stored, len(items))
	}
	if extractFailures != 0 {
		t.Fatalf("extractFailures = %d, want 0", extractFailures)
	}

	db := s.DB()

	var generic int
	if err := db.QueryRow(`SELECT COUNT(*) FROM resources WHERE resource_type = ?`, "zones_secondary_dns").Scan(&generic); err != nil {
		t.Fatalf("count resources: %v", err)
	}
	if generic != len(items) {
		t.Fatalf("resources count = %d, want %d (savepoint rollback must not undo generic insert)", generic, len(items))
	}

	var typed int
	typedQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s"`, "zones_secondary_dns")
	if err := db.QueryRow(typedQuery).Scan(&typed); err != nil {
		t.Fatalf("count zones_secondary_dns: %v", err)
	}
	if typed != 0 {
		t.Fatalf("zones_secondary_dns count = %d, want 0 (typed insert violated NOT NULL on %q)", typed, "zones_id")
	}
}

// TestUpsertBatch_KeysZonesSecondaryDnsByChildAndParent verifies dependent
// sub-collection rows with the same child id but different parent ids do not
// overwrite one another in either the generic resources table or the typed
// table. Regression for issue #2471.
func TestUpsertBatch_KeysZonesSecondaryDnsByChildAndParent(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	items := []json.RawMessage{
		json.RawMessage(`{"id": "shared_child", "zones_id": "parent_A"}`),
		json.RawMessage(`{"id": "shared", "zones_id": "child_parent_A"}`),
		json.RawMessage(`{"id": "shared_child", "zones_id": "parent_B"}`),
		json.RawMessage(`{"id": "other_child", "zones_id": "parent_A"}`),
	}
	stored, extractFailures, err := s.UpsertBatch("zones_secondary_dns", items)
	if err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}
	if stored != len(items) {
		t.Fatalf("stored = %d, want %d", stored, len(items))
	}
	if extractFailures != 0 {
		t.Fatalf("extractFailures = %d, want 0", extractFailures)
	}

	db := s.DB()

	var generic int
	if err := db.QueryRow(`SELECT COUNT(*) FROM resources WHERE resource_type = ?`, "zones_secondary_dns").Scan(&generic); err != nil {
		t.Fatalf("count resources: %v", err)
	}
	if generic != len(items) {
		t.Fatalf("resources count = %d, want %d (dependent rows collapsed on child id)", generic, len(items))
	}

	var typed int
	typedQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s"`, "zones_secondary_dns")
	if err := db.QueryRow(typedQuery).Scan(&typed); err != nil {
		t.Fatalf("count zones_secondary_dns: %v", err)
	}
	if typed != len(items) {
		t.Fatalf("zones_secondary_dns count = %d, want %d (typed rows collapsed on child id)", typed, len(items))
	}

	var parentMatches int
	parentQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s" WHERE "zones_id" = ?`, "zones_secondary_dns")
	if err := db.QueryRow(parentQuery, "parent_A").Scan(&parentMatches); err != nil {
		t.Fatalf("count by zones_id: %v", err)
	}
	if parentMatches != 2 {
		t.Fatalf("zones_id=parent_A count = %d, want 2", parentMatches)
	}
}

