// the NOT NULL parent FK column so the typed insert fails; the savepoint
// rolls back only the typed projection. The generic resources row inserted
// just before must survive. Regression for issue #1392, where a single
// outer transaction caused typed-table failures to cascade and silently
// discard every successfully fetched API row.
func TestUpsertBatch_TypedFailureDoesNotStrandSpectrumGeneric(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	// Items deliberately omit "zones_id" so the typed NOT NULL
	// constraint fires.
	items := []json.RawMessage{
		json.RawMessage(`{"id": "orphan-001"}`),
		json.RawMessage(`{"id": "orphan-002"}`),
		json.RawMessage(`{"id": "orphan-003"}`),
	}
	stored, extractFailures, err := s.UpsertBatch("spectrum", items)
	if err != nil {
		t.Fatalf("UpsertBatch: %v (typed-table failure must not propagate)", err)
	}
	if stored != len(items) {
		t.Fatalf("stored = %d, want %d (generic resources rows must land even when typed table fails)", stored, len(items))
	}
	if extractFailures != 0 {
		t.Fatalf("extractFailures = %d, want 0", extractFailures)
	}

	db := s.DB()

	var generic int
	if err := db.QueryRow(`SELECT COUNT(*) FROM resources WHERE resource_type = ?`, "spectrum").Scan(&generic); err != nil {
		t.Fatalf("count resources: %v", err)
	}
	if generic != len(items) {
		t.Fatalf("resources count = %d, want %d (savepoint rollback must not undo generic insert)", generic, len(items))
	}

	var typed int
	typedQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s"`, "spectrum")
	if err := db.QueryRow(typedQuery).Scan(&typed); err != nil {
		t.Fatalf("count spectrum: %v", err)
	}
	if typed != 0 {
		t.Fatalf("spectrum count = %d, want 0 (typed insert violated NOT NULL on %q)", typed, "zones_id")
	}
}

// TestUpsertBatch_KeysSpectrumByChildAndParent verifies dependent
// sub-collection rows with the same child id but different parent ids do not
// overwrite one another in either the generic resources table or the typed
// table. Regression for issue #2471.
func TestUpsertBatch_KeysSpectrumByChildAndParent(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	items := []json.RawMessage{
		json.RawMessage(`{"id": "shared_child", "zones_id": "parent_A"}`),
		json.RawMessage(`{"id": "shared", "zones_id": "child_parent_A"}`),
		json.RawMessage(`{"id": "shared_child", "zones_id": "parent_B"}`),
		json.RawMessage(`{"id": "other_child", "zones_id": "parent_A"}`),
	}
	stored, extractFailures, err := s.UpsertBatch("spectrum", items)
	if err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}
	if stored != len(items) {
		t.Fatalf("stored = %d, want %d", stored, len(items))
	}
	if extractFailures != 0 {
		t.Fatalf("extractFailures = %d, want 0", extractFailures)
	}

	db := s.DB()

	var generic int
	if err := db.QueryRow(`SELECT COUNT(*) FROM resources WHERE resource_type = ?`, "spectrum").Scan(&generic); err != nil {
		t.Fatalf("count resources: %v", err)
	}
	if generic != len(items) {
		t.Fatalf("resources count = %d, want %d (dependent rows collapsed on child id)", generic, len(items))
	}

	var typed int
	typedQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s"`, "spectrum")
	if err := db.QueryRow(typedQuery).Scan(&typed); err != nil {
		t.Fatalf("count spectrum: %v", err)
	}
	if typed != len(items) {
		t.Fatalf("spectrum count = %d, want %d (typed rows collapsed on child id)", typed, len(items))
	}

	var parentMatches int
	parentQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s" WHERE "zones_id" = ?`, "spectrum")
	if err := db.QueryRow(parentQuery, "parent_A").Scan(&parentMatches); err != nil {
		t.Fatalf("count by zones_id: %v", err)
	}
	if parentMatches != 2 {
		t.Fatalf("zones_id=parent_A count = %d, want 2", parentMatches)
	}
}

// TestUpsertBatch_SetsSpectrumParentID verifies that dependent-resource
// sync (which injects parent_id into each item's JSON) populates the typed
// parent_id column when items go through UpsertBatch. Regression for issue #268.
func TestUpsertBatch_SetsSpectrumParentID(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	items := []json.RawMessage{
		json.RawMessage(`{"id": "child-001", "zones_id": "parent-A", "parent_id": "parent-A"}`),
		json.RawMessage(`{"id": "child-002", "zones_id": "parent-A", "parent_id": "parent-A"}`),
		json.RawMessage(`{"id": "child-003", "zones_id": "parent-B", "parent_id": "parent-B"}`),
	}
	if _, _, err := s.UpsertBatch("spectrum", items); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}

	db := s.DB()

	var matchedA int
	parentQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s" WHERE parent_id = ?`, "spectrum")
	if err := db.QueryRow(parentQuery, "parent-A").Scan(&matchedA); err != nil {
		t.Fatalf("count by parent_id: %v", err)
	}
	if matchedA != 2 {
		t.Fatalf("parent_id=parent-A count = %d, want 2 (parent_id column not populated)", matchedA)
	}
}

// TestUpsertBatch_SpectrumSearchableViaGenericFTS verifies that a
// dependent-resource row stored via UpsertBatch — the exact path dependent
// sync uses (upsertResourceBatch -> UpsertBatch) — is reachable through the
// generic resources_fts index via Store.Search. That index is the substrate
// both `search` surfaces query (the empty-type search directly, and the
// non-FTS5 `--type spectrum` fallback), so populating it is the
// precondition issue #2629 reported missing — dependent resources stored in
// the typed table but absent from any FTS index. This asserts the store layer
// where the claimed defect lived; it does not exercise the CLI search wiring.
func TestUpsertBatch_SpectrumSearchableViaGenericFTS(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	// resources_fts indexes the full JSON blob, so a distinctive token in any
	// field is matchable regardless of which columns spectrum declares.
	const probe = "zqxjpp2629probe"
	items := []json.RawMessage{
		json.RawMessage(`{"id": "search-001", "pp_fts_probe": "` + probe + `", "zones_id": "parent-A", "parent_id": "parent-A"}`),
	}
	stored, _, err := s.UpsertBatch("spectrum", items)
	if err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}
	// Assert the probe row actually landed before searching for it: a PK
	// extraction miss would leave stored == 0, and the FTS check below would
	// then fail with a misleading "stored but not searchable" message.
	if stored != 1 {
		t.Fatalf("UpsertBatch stored %d rows, want 1 (probe row dropped before the FTS check)", stored)
	}

	results, err := s.Search(probe, 50)
	if err != nil {
		t.Fatalf("Search: %v", err)
	}
	if len(results) == 0 {
		t.Fatalf("dependent resource %q stored but not searchable via generic resources_fts (issue #2629)", "spectrum")
	}
}

